var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"경비행기를 타고 온다길래 놀러오는 줄은 알았지만…","JPN":"軽飛行機で来るというから、遊びに来るんだとばかり思っていたが……","ENG":"I assumed you were here for pleasure when I heard you came here on a light aircraft...","TWN":"聽說你坐小型飛機來，一開始我還以為你是來玩的……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"많고 많은 관광 명소들을 제쳐 두고 이런 폐허를 들르다니. 재밌는 취향이네.","JPN":"数多くある観光名所は差し置いて、こんな廃墟に寄るとは。面白い趣味だな。","ENG":"But you passed all the main tourist sites to come to these ruins. What an odd taste you have.","TWN":"撇開眾多旅遊景點不去，偏偏來這種鳥不生蛋的地方，品味真特別呢。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그래서? 폐허 탐방의 소감은 어때?","JPN":"それで？　廃墟を探索してみた感想は？","ENG":"So? What do you think about these ruins?","TWN":"說說吧？探險廢墟的感想如何？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리 실패가 있기 1년 전…","JPN":"管理失敗の1年前……","ENG":"A year before the Administration Failure...","TWN":"管理失敗的一年前……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 수석 연구원이 불현듯 사직서를 내고 떠났지.","JPN":"管理局の主席研究員が突然辞職願を出して出て行った。","ENG":"The Administration's chief researcher suddenly resigned and left.","TWN":"管理局的首席研究員突然遞交辭呈離開了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원칙대로 그녀는 부분적 기억소거 시술을 받은 뒤 사회로 복귀했고, 우리는 그 행적을 더 이상 추적하거나 기록하지 않았네.","JPN":"原則どおり、彼女は部分的な記憶消去の施術を受けて社会に復帰し、私たちはそれ以来彼女を追跡したり記録してはいなかった。","ENG":"As per principle, she underwent a partial memory wipe and returned to society, and we no longer tracked or recorded her movements.","TWN":"照規矩，她在接受了部分記憶消除手術後回歸了社會，我們便不再追蹤或記錄她的行蹤。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나중에 알게 된 바로는, 군의관 신분으로 활동하며 많은 침식증후군 환자들을 돕고 있었더군.","JPN":"後で判明した事実によると、軍医官の身分で活動しながら多くの侵食症候群の患者を助けていた。","ENG":"From what I found out later, she was working as an army surgeon, helping patients with Corruption Syndrome.","TWN":"但我後來才知道，她以軍醫的身份活動，幫助了許多侵蝕症候群患者。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"바로 이 병원에서 말이야.","JPN":"まさに、この病院で。","ENG":"At this very hospital, that is.","TWN":"就在這家醫院。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"환자들을 도왔다라… 그걸 도왔다고 불러도 되나?","JPN":"患者を助けた……それを助けたと言ってもいいのか？","ENG":"Helping patients... Can it be called helping?","TWN":"幫助患者……這也能叫幫助嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그 사람은 의사로서 결국 아무도 살리지 못했잖아.","JPN":"あの人は医者として結局誰1人救えなかったではないか。","ENG":"As a doctor, that person couldn't save anyone.","TWN":"那個時候的她作為醫生，最終誰也沒能救活。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그들을 치료하지 못한 건 의사의 잘못이 아니야.","JPN":"彼らを治療できなかったのは、医者のせいではない。","ENG":"It wasn't the doctor's fault that they couldn't be cured.","TWN":"沒能治好他們不是醫生的錯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식증후군은 질병 같은 게 아니니까.","JPN":"侵食症候群は病なんかではないのだからな。","ENG":"Because the Corruption Syndrome is not a sickness.","TWN":"侵蝕症候群並不是一種疾病。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…맞아. 안된다는 걸 알면서도 시도했지.","JPN":"……そうだ。駄目だとわかっていながらも止めなかった。","ENG":"...You're right. She knew it wouldn't work, but she tried anyway.","TWN":"……你說的沒錯。但她明知道不行，還是嘗試了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"고통 받는 환자들을 억지로 붙잡는 짓일 뿐이었어.","JPN":"苦しむ患者たちを無理やりこの世に留めておくだけだったんだ。","ENG":"But in the end, she was just keeping the suffering patients here against their will.","TWN":"後來才發現，那只是強行抓住患者受苦而已。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"결국 아무도 구하지 못한 그 사람은 의사라는 신분을 버리고, 온갖 수단을 동원해 침식을 연구했어.","JPN":"結局誰も救えなかったあの人は医者という身分を捨て、あらゆる手を使って侵食を研究した。","ENG":"Eventually, the one couldn't save anyone abandoned her position as a doctor and focused on researching the Corruption by using all means necessary.","TWN":"最終，那個沒能救下任何人的她放棄了醫生的身份，開始動用一切能用的手段研究侵蝕。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그리고 알게 된 거야.","JPN":"そしてわかったんだ。","ENG":"And that's when she realized.","TWN":"而且那時候她才知道。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"침식은 사람의 몸이 아니라 그 운명에 들러붙는 사신이란 걸.","JPN":"侵食は人間の体ではなくて、その運命にまとわりつく死神だということを。","ENG":"That the Corruption is not bound to a person's body, but is the death reaper that binds itself to their fate.","TWN":"侵蝕不是附在人身體上，而是附著在命運之上的死神。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"침식증후군에 걸린다는 건… 그 사람의 운명이 종점에 다다랐다는 신호일 뿐이란 걸.","JPN":"侵食症候群にかかるということは……その人の運命が終点に到達したという信号に過ぎないということを。","ENG":"Having Corruption Syndrome is... merely a signal that the person's fate has reached its end.","TWN":"感染侵蝕症候群……只是就表示那個人的命運已經走到了盡頭。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 계획을 바꾼 건가?","JPN":"それで計画を修正したのか？","ENG":"Is that why you changed course?","TWN":"所以你才改變了計畫嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"진리 연구부 같은 말장난을 하며, 사람의 운명에 직접 손을 대기로?","JPN":"真理研究部だのと口実をつけて、人の運命に直接手を出すように？","ENG":"Calling it the Veritas Research Department and directly interfering with other people's fates?","TWN":"打著真理研究部的旗幟，實則直接干涉別人的命運嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"당신도 비슷하지 않아?","JPN":"君も似たようなものだろう。","ENG":"Aren't you the same?","TWN":"別忘了，你和我是一樣的。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"한 조각의 기적을 위해 굴레에 갇힌 이들의 영혼을 이용했으면서.","JPN":"一欠片の奇跡のために、束縛された者たちの魂を利用したくせに。","ENG":"You've used the souls trapped in an endless loop all for a fragment of a miracle.","TWN":"為了那點零星的奇蹟，你利用了被束縛在這個牢籠中的靈魂。"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"단지 조금 더 인도적인 방법을 골랐다는 이유로, 지금까지의 그 모든 방관과 방조가 옳았던 일이 되는 걸까?","JPN":"ただ少し人道的な方法を選んだという理由で、今までしてきた傍観と幇助が正しかったことになるのか？","ENG":"Just because you chose a slightly more humane method, does that make up for all your neglecting and abetting up until now?","TWN":"僅僅是因為選擇了更人道的方法，難道之前所有的袖手旁觀和縱容就變成正確的了嗎？"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"나도 내가 한 일들을 용서 받을 생각은 없어. 그런 추잡한 실험을 정의라고 생각하지도 않아.","JPN":"私も自分がやってきたことを許してもらう気はない。あんな汚らわしい実験を正義とも思っていない。","ENG":"I have no intention of being forgiven for what I did. And I don't think those crude experiments are justice.","TWN":"我不指望有人能原諒我所做的事。並且我從未認為那種骯髒的實驗是正義的。"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그저 결과를 얻을 수만 있다면, 내가 옳다고 생각한 일을 행할 뿐.","JPN":"ただ結果さえ得られれば、私が正しいと思ったことを実行するだけ。","ENG":"But as long as I get results, I do what I think is right.","TWN":"只要能得到期望的結果，我會做我認為正確的事。"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"당신도 그렇지?","JPN":"君もそうだろう？","ENG":"Aren't you the same?","TWN":"你不也是這樣嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};